// ============================================================
// HydraNet - Notifications API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET /api/notifications - List notifications for a user
// Query params: userId (required), userType (required: admin, utilityMgr, dmaMgr, engineer)
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const userId = searchParams.get('userId')
    const userType = searchParams.get('userType') // 'admin' | 'utilityMgr' | 'dmaMgr' | 'engineer'

    if (!userId || !userType) {
      return NextResponse.json({ error: 'userId and userType are required' }, { status: 400 })
    }

    // Build the where clause based on user type
    const whereClause: {
      adminId?: string
      utilityMgrId?: string
      dmaMgrId?: string
      engineerId?: string
    } = {}

    switch (userType) {
      case 'admin':
        whereClause.adminId = userId
        break
      case 'utilityMgr':
        whereClause.utilityMgrId = userId
        break
      case 'dmaMgr':
        whereClause.dmaMgrId = userId
        break
      case 'engineer':
        whereClause.engineerId = userId
        break
      default:
        return NextResponse.json({ error: 'Invalid userType' }, { status: 400 })
    }

    const notifications = await prisma.notification.findMany({
      where: whereClause,
      orderBy: { createdAt: 'desc' },
      take: 50,
    })

    return NextResponse.json(notifications)
  } catch (error) {
    console.error('Error fetching notifications:', error)
    return NextResponse.json({ error: 'Failed to fetch notifications' }, { status: 500 })
  }
}

// PUT /api/notifications - Mark notification as read
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    // Mark all notifications as read for a user
    if (data.markAll && data.userId && data.userType) {
      const whereClause: {
        adminId?: string
        utilityMgrId?: string
        dmaMgrId?: string
        engineerId?: string
      } = {}

      switch (data.userType) {
        case 'admin':
          whereClause.adminId = data.userId
          break
        case 'utilityMgr':
          whereClause.utilityMgrId = data.userId
          break
        case 'dmaMgr':
          whereClause.dmaMgrId = data.userId
          break
        case 'engineer':
          whereClause.engineerId = data.userId
          break
        default:
          return NextResponse.json({ error: 'Invalid userType' }, { status: 400 })
      }

      await prisma.notification.updateMany({
        where: whereClause,
        data: { read: true },
      })
      return NextResponse.json({ message: 'All notifications marked as read' })
    }

    // Mark single notification as read
    if (data.id) {
      const notification = await prisma.notification.update({
        where: { id: data.id },
        data: { read: true },
      })
      return NextResponse.json(notification)
    }

    return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
  } catch (error) {
    console.error('Error updating notification:', error)
    return NextResponse.json({ error: 'Failed to update notification' }, { status: 500 })
  }
}

// POST /api/notifications - Create a notification
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Build the create data based on user type
    const createData: {
      title: string
      message: string
      type?: 'info' | 'warning' | 'success' | 'error'
      link?: string
      adminId?: string
      utilityMgrId?: string
      dmaMgrId?: string
      engineerId?: string
    } = {
      title: data.title,
      message: data.message,
      ...(data.type && { type: data.type }),
      ...(data.link && { link: data.link }),
    }

    // Add the appropriate user relation
    if (data.adminId) {
      createData.adminId = data.adminId
    } else if (data.utilityMgrId) {
      createData.utilityMgrId = data.utilityMgrId
    } else if (data.dmaMgrId) {
      createData.dmaMgrId = data.dmaMgrId
    } else if (data.engineerId) {
      createData.engineerId = data.engineerId
    } else {
      return NextResponse.json({ error: 'At least one user ID is required' }, { status: 400 })
    }

    const notification = await prisma.notification.create({
      data: createData,
    })

    return NextResponse.json(notification, { status: 201 })
  } catch (error) {
    console.error('Error creating notification:', error)
    return NextResponse.json({ error: 'Failed to create notification' }, { status: 500 })
  }
}